def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0.1:
            base_score = np.exp(-7 * ratio) * (1 - ratio)**2 + np.sin(ratio * 10)
        elif 0.1 <= ratio < 0.3:
            base_score = (np.log1p(ratio*7) * 5 - ratio**3) * np.cos(np.pi * ratio)
        elif 0.3 <= ratio < 0.6:
            base_score = np.sin(ratio * 12)**2 + 1/(1 + np.exp(-30*(ratio - 0.45)))
        elif 0.6 <= ratio < 0.85:
            base_score = np.tanh(10*(ratio - 0.75)) + np.cos(ratio * 15) * np.exp(-3*ratio)
        else:
            base_score = 1 / (1 + np.exp(-40 * (ratio - 0.9))) + 0.7 * np.sin(5 * ratio)
        penalty = 0
        for j in range(1, 9):
            mod_val = (item * j * np.sin(ratio * 10)) % (capacity + 1)
            frac = mod_val / (capacity * j + 0.5)
            if frac < 0.03:
                penalty += frac * 4
            elif 0.03 <= frac < 0.15:
                penalty += frac * 2.2
            elif 0.15 <= frac < 0.4:
                penalty += frac * 0.8
            else:
                penalty += (frac**2) / (j + ratio + 1)
        extra_penalty = 0
        for k in range(1, 6):
            threshold = 0.35 * k
            if ratio > threshold:
                val = np.exp(-k * ratio**2) * k**2
                extra_penalty += val if val < 1.5 else 1.5
            else:
                log_val = np.log1p(k**3 * ratio + k**2)
                extra_penalty += log_val / (k + 3)
        complexity_factor = 0
        for m in range(1, 5):
            for n in range(1, 5):
                combined = (ratio * m + n * 0.5) % 1
                if combined < 0.2:
                    complexity_factor += np.sin(combined * 2 * np.pi) / (m * n + 1)
                elif 0.2 <= combined < 0.6:
                    complexity_factor += np.cos(combined * 3 * np.pi) / (m + n + 1)
                else:
                    complexity_factor += (combined ** 3) / (m * n + 2)
        if capacity % 2 == 0 and capacity % 7 == 0:
            priority_score = base_score + penalty * 0.75 + extra_penalty * 1.1 + complexity_factor * 0.95
        elif capacity % 4 == 0 or capacity % 6 == 0:
            priority_score = base_score + penalty * 1.3 + extra_penalty * 0.85 + complexity_factor * 0.65
        elif capacity % 9 == 0:
            priority_score = base_score + penalty * 0.6 + extra_penalty * 1.4 + complexity_factor * 0.4
        else:
            priority_score = base_score + penalty + extra_penalty + complexity_factor
        if priority_score < 0:
            priority_score = 0
        priorities[i] = priority_score
    return priorities
